choose.when:
SELECT e.EMP_NO || '|' || e.SALARY_ITEM_CODE || '|' || TO_CHAR(e.START_DTM, 'YYYYMMDD') AS histKey, 'EMP_ALLOW' AS tab, CASE WHEN TRUNC(SYSDATE) BETWEEN TRUNC(NVL(e.START_DTM, DATE '1900-01-01')) AND TRUNC(NVL(e.END_DTM, DATE '9999-12-31')) THEN 'CURRENT' ELSE 'ENDED' END AS status, d.DEPT_NM AS deptNm, p.POS_CD AS posCd, p.POS_NM AS posNm, em.EMP_NM AS empNm, em.EMP_NO AS empNo, e.SALARY_ITEM_CODE AS salaryItemCode, s.SALARY_ITEM_NAME AS salaryItemName, s.ITEM_TYPE AS itemType, s.TAX_TYPE AS taxType, NVL(e.ITEM_AMOUNT, 0) AS itemAmount, TO_CHAR(e.START_DTM, 'YYYY-MM-DD') AS startDtm, TO_CHAR(e.END_DTM, 'YYYY-MM-DD') AS endDtm FROM EMP_SALARY_ITEM e JOIN EMP em ON em.EMP_NO = e.EMP_NO LEFT JOIN DEPT d ON d.DEPT_CD = em.DEPT_CD LEFT JOIN POSITION_MST p ON p.POS_CD = em.POS_CD LEFT JOIN SALARY_ITEM s ON s.SALARY_ITEM_CODE = e.SALARY_ITEM_CODE
AND TRUNC(NVL(e.END_DTM, DATE '9999-12-31')) >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND TRUNC(NVL(e.START_DTM, DATE '1900-01-01')) <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND d.DEPT_NM = #{deptNm}
AND p.POS_CD = #{posCd}
AND em.EMP_NM LIKE '%' || #{empNm} || '%'
AND em.EMP_NO LIKE '%' || #{empNo} || '%'
AND e.SALARY_ITEM_CODE = #{salaryItemCode}
AND s.TAX_TYPE = #{taxType}
AND TRUNC(SYSDATE) BETWEEN TRUNC(NVL(e.START_DTM, DATE '1900-01-01')) AND TRUNC(NVL(e.END_DTM, DATE '9999-12-31'))
AND NOT (TRUNC(SYSDATE) BETWEEN TRUNC(NVL(e.START_DTM, DATE '1900-01-01')) AND TRUNC(NVL(e.END_DTM, DATE '9999-12-31')))
ORDER BY e.START_DTM DESC, em.EMP_NM ASC, e.SALARY_ITEM_CODE ASC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

choose.otherwise:
SELECT TO_CHAR(pr.PAYROLL_NO) AS histKey, 'PAYROLL' AS tab, pr.PAYROLL_NO AS payrollNo, pr.PAY_YYYYMM AS payYyyymm, pr.CONFIRM_YN AS confirmYn, d.DEPT_NM AS deptNm, p.POS_CD AS posCd, p.POS_NM AS posNm, em.EMP_NM AS empNm, em.EMP_NO AS empNo, NVL(pr.TOTAL_PAY_AMT, 0) AS totalPayAmt, NVL(pr.TOTAL_DEDUCT_AMT, 0) AS totalDeductAmt, NVL(pr.NET_PAY_AMT, 0) AS netPayAmt, TO_CHAR(pr.CREATED_DTM, 'YYYY-MM-DD') AS createdDtm FROM PAYROLL pr JOIN EMP em ON em.EMP_NO = pr.EMP_NO LEFT JOIN DEPT d ON d.DEPT_CD = em.DEPT_CD LEFT JOIN POSITION_MST p ON p.POS_CD = em.POS_CD
AND pr.PAY_YYYYMM >= #{payMonthFrom}
AND pr.PAY_YYYYMM <= #{payMonthTo}
AND d.DEPT_NM = #{deptNm}
AND p.POS_CD = #{posCd}
AND em.EMP_NM LIKE '%' || #{empNm} || '%'
AND em.EMP_NO LIKE '%' || #{empNo} || '%'
AND pr.CONFIRM_YN = #{confirmYn}
ORDER BY pr.PAY_YYYYMM DESC, pr.CREATED_DTM DESC, pr.PAYROLL_NO DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

choose.when:
SELECT COUNT(1) FROM EMP_SALARY_ITEM e JOIN EMP em ON em.EMP_NO = e.EMP_NO LEFT JOIN DEPT d ON d.DEPT_CD = em.DEPT_CD LEFT JOIN POSITION_MST p ON p.POS_CD = em.POS_CD LEFT JOIN SALARY_ITEM s ON s.SALARY_ITEM_CODE = e.SALARY_ITEM_CODE
AND TRUNC(NVL(e.END_DTM, DATE '9999-12-31')) >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND TRUNC(NVL(e.START_DTM, DATE '1900-01-01')) <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND d.DEPT_NM = #{deptNm}
AND p.POS_CD = #{posCd}
AND em.EMP_NM LIKE '%' || #{empNm} || '%'
AND em.EMP_NO LIKE '%' || #{empNo} || '%'
AND e.SALARY_ITEM_CODE = #{salaryItemCode}
AND s.TAX_TYPE = #{taxType}
AND TRUNC(SYSDATE) BETWEEN TRUNC(NVL(e.START_DTM, DATE '1900-01-01')) AND TRUNC(NVL(e.END_DTM, DATE '9999-12-31'))
AND NOT (TRUNC(SYSDATE) BETWEEN TRUNC(NVL(e.START_DTM, DATE '1900-01-01')) AND TRUNC(NVL(e.END_DTM, DATE '9999-12-31')))

choose.otherwise:
SELECT COUNT(1)
FROM PAYROLL pr
JOIN EMP em ON em.EMP_NO = pr.EMP_NO
LEFT JOIN DEPT d ON d.DEPT_CD = em.DEPT_CD
LEFT JOIN POSITION_MST p ON p.POS_CD = em.POS_CD


    AND pr.PAY_YYYYMM >= #{payMonthFrom}


    AND pr.PAY_YYYYMM <= #{payMonthTo}


    AND d.DEPT_NM = #{deptNm}


    AND p.POS_CD = #{posCd}


    AND em.EMP_NM LIKE '%' || #{empNm} || '%'


    AND em.EMP_NO LIKE '%' || #{empNo} || '%'


    AND pr.CONFIRM_YN = #{confirmYn}
